// Santi AEO — loads the analyzer from your deployed site and runs it.
// Single source of truth: api/aeo-core.js in your git repo. Push git -> this
// fetches the latest version automatically (no re-import needed).
// If you host aeo-core.js elsewhere, change CORE_URL below.
const CORE_URL = 'https://santi.co.za/api/aeo-core.js';

const src = await this.helpers.httpRequest({ url: CORE_URL, json: false });
const mod = { exports: {} };
(new Function('module', 'exports', src))(mod, mod.exports);
const core = mod.exports;

const httpGet = async (url) => {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers: { 'User-Agent': 'SantiAEO-Bot/1.0 (+https://santi.co.za/aeo)' },
    timeout: 9000,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
    json: false,
  });
  const body = typeof res.body === 'string' ? res.body : (res.body == null ? '' : JSON.stringify(res.body));
  return { status: res.statusCode, body, finalUrl: url };
};

const input = $input.first().json;
const url = (input.query && input.query.url) || (input.body && input.body.url) || input.url;

try {
  const report = await core.analyze(url, httpGet);
  return [{ json: report }];
} catch (e) {
  return [{ json: { error: (e && e.message) || 'Something went wrong.' } }];
}
